import{_ as a,o as i,c as e,ag as r}from"./chunks/framework.ePeAWSvT.js";const _=JSON.parse('{"title":"Screen Policy: 오시는 길","description":"","frontmatter":{},"headers":[],"relativePath":"오시는길_Screen_Policy.md","filePath":"오시는길_Screen_Policy.md"}'),t={name:"오시는길_Screen_Policy.md"};function o(h,l,u,n,c,d){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="screen-policy-오시는-길" tabindex="-1">Screen Policy: 오시는 길 <a class="header-anchor" href="#screen-policy-오시는-길" aria-label="Permalink to &quot;Screen Policy: 오시는 길&quot;">​</a></h1><hr><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><ul><li>SCREEN_NAME: 오시는 길</li><li>화면 목적: 성원애드피아 매장(성수동·충무로·인현동)의 위치, 연락처, 교통편 안내</li></ul><hr><h2 id="■-ui-구성-요소" tabindex="-1">■ UI 구성 요소 <a class="header-anchor" href="#■-ui-구성-요소" aria-label="Permalink to &quot;■ UI 구성 요소&quot;">​</a></h2><h3 id="탭-메뉴" tabindex="-1">[탭 메뉴] <a class="header-anchor" href="#탭-메뉴" aria-label="Permalink to &quot;[탭 메뉴]&quot;">​</a></h3><ul><li>구성: 성수동 / 충무로 / 인현동</li><li>기본 선택: 성수동 (첫 진입 시)</li><li>UI 정책: 선택된 탭은 활성 상태로 표시, 탭 전환 시 하단 콘텐츠 영역 교체</li><li>탭 간 정보 구성: 거의 동일하나 일부 항목 상이할 수 있음 → 현업 확인 필요사항 참조</li></ul><h3 id="지도-영역" tabindex="-1">[지도 영역] <a class="header-anchor" href="#지도-영역" aria-label="Permalink to &quot;[지도 영역]&quot;">​</a></h3><ul><li>위치: 탭 콘텐츠 상단</li><li>UI 정책: 해당 매장 위치를 지도로 표시</li></ul><h3 id="매장-정보-영역" tabindex="-1">[매장 정보 영역] <a class="header-anchor" href="#매장-정보-영역" aria-label="Permalink to &quot;[매장 정보 영역]&quot;">​</a></h3><ul><li>표시 항목: <ul><li>주소</li><li>매장명</li><li>매장 태그 (예: 공장 · 접수 · 출고 · 24시간 무인출고 운영)</li><li>전화번호</li><li>오시는 길 (텍스트 안내)</li><li>지하철 이용 시</li><li>버스 이용 시</li></ul></li></ul><h3 id="전화번호" tabindex="-1">[전화번호] <a class="header-anchor" href="#전화번호" aria-label="Permalink to &quot;[전화번호]&quot;">​</a></h3><ul><li>UI 정책: <ul><li>PC: 클릭 시 동작 없음 (텍스트 표시만)</li><li>모바일: 클릭 시 전화 앱 바로 연결</li></ul></li></ul><h3 id="공유-버튼" tabindex="-1">[공유 버튼] <a class="header-anchor" href="#공유-버튼" aria-label="Permalink to &quot;[공유 버튼]&quot;">​</a></h3><ul><li>UI 정책: <ul><li>PC: 클릭 시 현재 페이지 URL 클립보드 복사 → &quot;링크가 복사되었습니다&quot; 토스트 메시지 표시</li><li>모바일: 클릭 시 OS 기본 공유 시트 호출</li></ul></li></ul><hr><h2 id="■-화면-결과" tabindex="-1">■ 화면 결과 <a class="header-anchor" href="#■-화면-결과" aria-label="Permalink to &quot;■ 화면 결과&quot;">​</a></h2><ul><li>탭 전환 시: 선택한 매장의 지도 및 정보로 즉시 교체 표시</li><li>공유 버튼 클릭 시 (PC): 하단 토스트 메시지 &quot;링크가 복사되었습니다&quot; 노출 후 자동 소멸</li><li>공유 버튼 클릭 시 (모바일): OS 기본 공유 시트 호출</li></ul><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><ul><li>지도 로딩 실패 시: 지도 영역에 &quot;지도를 불러올 수 없습니다&quot; 안내 문구 표시</li><li>모바일 공유 시트 미지원 환경: URL 클립보드 복사로 fallback 처리</li></ul><hr><h2 id="■-내부-확인-필요사항" tabindex="-1">■ 내부 확인 필요사항 <a class="header-anchor" href="#■-내부-확인-필요사항" aria-label="Permalink to &quot;■ 내부 확인 필요사항&quot;">​</a></h2><ul><li><p>I1. 지도 서비스 종류</p><ul><li>선택된 상태: 내부 확인 필요 (카카오맵 / 네이버맵 / 구글맵 중 결정 필요)</li></ul></li><li><p>I2. 충무로·인현동 탭의 표시 항목 구성</p><ul><li>선택된 상태: 성수동과 거의 동일하나 일부 상이할 수 있음 → 탭별 표시 항목 및 태그 목록 확정 필요</li></ul></li></ul><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><ul><li>충무로 탭 화면 - 매장 정보 및 태그 항목 확인 필요</li><li>인현동 탭 화면 - 매장 정보 및 태그 항목 확인 필요</li></ul>',28)])])}const q=a(t,[["render",o]]);export{_ as __pageData,q as default};
